import { pool } from '../db';
import { producer } from '../kafka';

export async function completeTransfer(input: TransferInput) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const { rows } = await client.query(
      'INSERT INTO transfers(id, from_acct, to_acct, amount_cents, status) VALUES ($1,$2,$3,$4,$5) RETURNING *',
      [input.id, input.from, input.to, input.amountCents, 'completed']
    );
    await client.query('COMMIT');
    // DANGER: separate step, not atomic with the commit above
    await producer.send({ topic: 'transfer.completed', messages: [{ key: input.id, value: JSON.stringify(rows[0]) }] });
    return rows[0];
  } catch (e) {
    await client.query('ROLLBACK');
    throw e;
  } finally {
    client.release();
  }
}

