export async function completeTransfer(input: TransferInput) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const { rows } = await client.query(
      'INSERT INTO transfers(id, from_acct, to_acct, amount_cents, status) VALUES ($1,$2,$3,$4,$5) RETURNING *',
      [input.id, input.from, input.to, input.amountCents, 'completed']
