    throw e;
  } finally {
    client.release();
  }
}

import { pool } from '../db';
import { producer } from '../kafka';

export async function relayBatch(batch = 200) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const { rows } = await client.query(
      `SELECT id, event_id, topic, aggregate_id, payload FROM outbox_events
       WHERE published_at IS NULL
       ORDER BY created_at
       FOR UPDATE SKIP LOCKED
       LIMIT $1`, [batch]
    );
    if (rows.length === 0) { await client.query('COMMIT'); return 0; }
    await producer.send({
      topic: rows[0].topic,
      messages: rows.map(r => ({ key: r.aggregate_id, value: JSON.stringify(r.payload), headers: { 'event-id': r.event_id } }))
    });
    await client.query(
      `UPDATE outbox_events SET published_at = now() WHERE id = ANY($1)`,
      [rows.map(r => r.id)]
    );
    await client.query('COMMIT');
    return rows.length;
  } catch (e) {
    await client.query('ROLLBACK');
    throw e;
  } finally {
    client.release();
  }
}

