import Stripe from 'stripe';
import { pool } from '../db';
const stripe = new Stripe(process.env.STRIPE_KEY!);

export async function handler(req: Request) {
  const event = stripe.webhooks.constructEvent(req.rawBody, req.headers['stripe-signature']!, process.env.WHSEC!);
  if (event.type !== 'payment_intent.succeeded') return new Response('ignored', { status: 200 });
  const pi = event.data.object as Stripe.PaymentIntent;
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    try {
      await client.query('INSERT INTO processed_webhook_events(event_id, source) VALUES ($1, $2)', [event.id, 'stripe']);
    } catch (e: any) {
      if (e.code === '23505') { await client.query('ROLLBACK'); return new Response('duplicate', { status: 200 }); }
      throw e;
    }
    await client.query('UPDATE orders SET status = $1 WHERE id = $2', ['paid', pi.metadata.order_id]);
    await client.query('UPDATE inventory SET qty = qty - 1 WHERE sku = $1 AND qty > 0', [pi.metadata.sku]);
    await client.query(
      'INSERT INTO outbox_events(event_id, topic, aggregate_id, payload) VALUES ($1,$2,$3,$4)',
      [event.id, 'fulfillment.requested', pi.metadata.order_id, JSON.stringify({ orderId: pi.metadata.order_id })]
    );
    await client.query('COMMIT');
    return new Response('ok', { status: 200 });
  } catch (e) { await client.query('ROLLBACK'); throw e; }
  finally { client.release(); }
}

package booking

func BookTrip(ctx context.Context, req TripRequest) (*Trip, error) {
	hotel, err := hotelAPI.Book(ctx, req.Hotel)
	if err != nil {
		return nil, err
	}
	flight, err := flightAPI.Book(ctx, req.Flight)
	if err != nil {
		return nil, err // hotel already booked and charged, never cancelled
	}
	car, err := carAPI.Book(ctx, req.Car)
	if err != nil {
		return nil, err // hotel + flight booked, both leak
	}
	return &Trip{Hotel: hotel, Flight: flight, Car: car}, nil
}

package booking

type Step struct {
	Name       string
	Forward    func(ctx context.Context, s *Saga) (string, error)
	Compensate func(ctx context.Context, s *Saga, bookingID string) error
}

func (o *Orchestrator) Run(ctx context.Context, s *Saga, steps []Step) error {
	done := []struct{ Step; id string }{}
	for _, st := range steps {
		id, err := st.Forward(ctx, s)
		if err != nil {
			o.compensate(ctx, s, done) // reverse order
			o.store.SetState(ctx, s.ID, "COMPENSATED")
			return fmt.Errorf("step %s failed: %w", st.Name, err)
		}
		o.store.RecordStep(ctx, s.ID, st.Name, id) // persist before next step
		done = append(done, struct{ Step; id string }{st, id})
	}
	o.store.SetState(ctx, s.ID, "COMMITTED")
	return nil
}

func (o *Orchestrator) compensate(ctx context.Context, s *Saga, done []struct{ Step; id string }) {
	for i := len(done) - 1; i >= 0; i-- {
		d := done[i]
		_ = d.Compensate(ctx, s, d.id) // idempotent; safe to retry
	}
}

package booking

func carStep() Step {
	return Step{
		Name: "car",
		Forward: func(ctx context.Context, s *Saga) (string, error) {
			return carAPI.Book(ctx, s.Req.Car, idemKey(s.ID, "car"))
		},
		Compensate: func(ctx context.Context, s *Saga, id string) error {
			return carAPI.Cancel(ctx, id, idemKey(s.ID, "car-cancel")) // idempotent cancel
		},
	}
}

func idemKey(sagaID, op string) string { return sagaID + ":" + op }

package booking

func (o *Orchestrator) RecoverStale(ctx context.Context) error {
	stale, err := o.store.PendingOlderThan(ctx, 2*time.Minute)
	if err != nil { return err }
	for _, s := range stale {
		// rebuild done-set from persisted booking ids, then compensate
		o.resumeOrCompensate(ctx, s)
	}
	return nil
}

import { db } from '../db';

export async function debit(walletId: string, amount: number) {
  const { rows } = await db.query('SELECT balance FROM wallets WHERE id = $1', [walletId]);
  const current = rows[0].balance;
  if (current < amount) throw new Error('insufficient');
  const next = current - amount; // read-modify-write, not atomic
  await db.query('UPDATE wallets SET balance = $1 WHERE id = $2', [next, walletId]);
  return next;
}

