import { pool } from '../db';

export async function debit(walletId: string, amount: number, reason: string) {
  for (let attempt = 0; attempt < 5; attempt++) {
    const client = await pool.connect();
    try {
      await client.query('BEGIN');
      const { rowCount } = await client.query(
        `UPDATE wallets SET balance = balance - $2, version = version + 1
         WHERE id = $1 AND balance >= $2`, [walletId, amount]
      );
      if (rowCount === 0) {
        await client.query('ROLLBACK');
        const { rows } = await pool.query('SELECT balance FROM wallets WHERE id = $1', [walletId]);
        if (rows[0].balance < amount) throw new InsufficientFundsError(walletId);
        continue; // lost the race, retry
      }
      await client.query('INSERT INTO wallet_ledger(wallet_id, delta, reason) VALUES ($1, $2, $3)', [walletId, -amount, reason]);
      await client.query('COMMIT');
      return;
    } catch (e) { await client.query('ROLLBACK'); throw e; }
    finally { client.release(); }
  }
  throw new Error('debit contention exceeded retries');
}

import { pool } from '../db';

export async function credit(walletId: string, amount: number, reason: string) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    await client.query('UPDATE wallets SET balance = balance + $2, version = version + 1 WHERE id = $1', [walletId, amount]);
    await client.query('INSERT INTO wallet_ledger(wallet_id, delta, reason) VALUES ($1, $2, $3)', [walletId, amount, reason]);
    await client.query('COMMIT');
  } catch (e) { await client.query('ROLLBACK'); throw e; }
  finally { client.release(); }
}

