CREATE TABLE idempotency_keys (
  key TEXT PRIMARY KEY,
  request_hash TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'pending',
  response JSONB,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX idem_sweep_idx ON idempotency_keys (created_at);

import { processor } from '../processor';
import { pool } from '../db';
import { createHash } from 'crypto';

export async function createPayment(key: string, req: PaymentReq) {
  const hash = createHash('sha256').update(JSON.stringify(req)).digest('hex');
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const claim = await client.query(
      `INSERT INTO idempotency_keys(key, request_hash) VALUES ($1,$2)
       ON CONFLICT (key) DO NOTHING RETURNING key`, [key, hash]
    );
    if (claim.rowCount === 0) {
      await client.query('COMMIT');
      return await replayStored(key, hash); // duplicate: return cached or wait for pending
    }
    await client.query('COMMIT');
  } finally { client.release(); }
  // we own the key: do the side effect exactly once
  const charge = await processor.charge({ amount: req.amount, source: req.source });
  const response = { paymentId: req.id, processorRef: charge.id };
  await pool.query(
    `UPDATE idempotency_keys SET status='done', response=$2 WHERE key=$1`, [key, JSON.stringify(response)]
  );
  await pool.query('INSERT INTO payments(id, amount, processor_ref) VALUES ($1,$2,$3)', [req.id, req.amount, charge.id]);
  return response;
}

import { pool } from '../db';

export async function replayStored(key: string, hash: string) {
  for (let i = 0; i < 20; i++) {
    const { rows } = await pool.query('SELECT request_hash, status, response FROM idempotency_keys WHERE key=$1', [key]);
    const row = rows[0];
    if (row.request_hash !== hash) { const e: any = new Error('idempotency key reused with different body'); e.status = 422; throw e; }
    if (row.status === 'done') return row.response;
    await new Promise(r => setTimeout(r, 150)); // pending: wait for the owner to finish
  }
  const e: any = new Error('idempotent request still processing'); e.status = 409; throw e;
}

