await consumer.run({
  autoCommit: false,
  eachMessage: async ({ topic, partition, message }) => {
    const evt = JSON.parse(message.value!.toString());
    const next = Number(message.offset) + 1;
    const client = await pool.connect();
    try {
      await client.query('BEGIN');
      await client.query(
        `UPDATE shipments SET status=$1, scan_count = scan_count + 1, last_applied_seq=$3
         WHERE id=$2 AND $3 > last_applied_seq`, [evt.status, evt.shipmentId, evt.seq]
      );
      await client.query(
        `INSERT INTO consumer_offsets(topic, partition, next_offset) VALUES ($1,$2,$3)
         ON CONFLICT (topic, partition) DO UPDATE SET next_offset = EXCLUDED.next_offset`,
        [topic, partition, next]
      );
      await client.query('COMMIT');
    } catch (e) { await client.query('ROLLBACK'); throw e; }
    finally { client.release(); }
  }
});

consumer.on(consumer.events.GROUP_JOIN, async ({ payload }) => {
  for (const { topic, partitions } of payload.memberAssignment ? assigned(payload) : []) {
    for (const p of partitions) {
      const { rows } = await pool.query('SELECT next_offset FROM consumer_offsets WHERE topic=$1 AND partition=$2', [topic, p]);
      if (rows[0]) consumer.seek({ topic, partition: p, offset: rows[0].next_offset.toString() });
    }
  }
});

async function placeOrder(order) {
  await db.collection('orders').insertOne(order);
  await db.collection('order_items').insertMany(order.items.map(i => ({ ...i, orderId: order._id })));
  await db.collection('seller_balances').updateOne(
    { sellerId: order.sellerId },
    { $inc: { pending: order.total } },
    { upsert: true }
  );
  return order._id;
}

async function placeOrder(client, order) {
  const session = client.startSession();
  try {
    let id;
    await session.withTransaction(async () => {
      const orders = client.db().collection('orders');
      await orders.insertOne(order, { session }); // unique _id => duplicate placement throws 11000
      await client.db().collection('order_items').insertMany(
        order.items.map(i => ({ ...i, orderId: order._id })), { session }
      );
      await client.db().collection('seller_balances').updateOne(
        { sellerId: order.sellerId },
        { $inc: { pending: order.total } },
        { upsert: true, session }
      );
      id = order._id;
    }, { writeConcern: { w: 'majority' }, readConcern: { level: 'snapshot' } });
    return id;
  } finally { await session.endSession(); }
}

