async function handler(req, res) {
  try {
    const id = await placeOrder(client, { ...req.body, idempotencyKey: req.headers['idempotency-key'] });
    res.json({ orderId: id });
  } catch (e) {
    if (e.code === 11000) return res.status(200).json({ orderId: req.body._id, replay: true });
    throw e;
  }
}

export async function updateProfile(id: string, patch: Patch) {
  await db.query('UPDATE profiles SET bio=$1, updated_at=now() WHERE id=$2', [patch.bio, id]);
  await redis.del(`profile:${id}`); // race: a concurrent read may repopulate from a lagging replica
