export async function getProfile(id: string) {
  const cached = await redis.get(`profile:${id}`);
  if (cached) return JSON.parse(cached);
  const { rows } = await readReplica.query('SELECT * FROM profiles WHERE id=$1', [id]); // may be stale
  await redis.set(`profile:${id}`, JSON.stringify(rows[0]), 'EX', 600);
  return rows[0];
}

export async function updateProfile(id: string, patch: Patch) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const { rows } = await client.query(
      'UPDATE profiles SET bio=$1, version=version+1, updated_at=now() WHERE id=$2 RETURNING version',
      [patch.bio, id]
    );
    await client.query(
      'INSERT INTO outbox_events(event_id, topic, aggregate_id, payload) VALUES (gen_random_uuid(), $1, $2, $3)',
      ['profile.invalidate', id, JSON.stringify({ id, version: rows[0].version })]
    );
    await redis.set(`profile:min-version:${id}`, rows[0].version, 'EX', 5); // floor for cacheable version
    await client.query('COMMIT');
  } catch (e) { await client.query('ROLLBACK'); throw e; }
  finally { client.release(); }
}

// relay handler for 'profile.invalidate'
export async function onInvalidate(evt: { id: string }) {
  await redis.del(`profile:${evt.id}`);
  setTimeout(() => redis.del(`profile:${evt.id}`).catch(() => {}), 200); // wipe any stale repopulation past replica lag
}

export async function getProfile(id: string) {
  const cached = await redis.get(`profile:${id}`);
  if (cached) return JSON.parse(cached).data;
  const { rows } = await readReplica.query('SELECT *, version FROM profiles WHERE id=$1', [id]);
  const floor = Number((await redis.get(`profile:min-version:${id}`)) ?? 0);
  if (rows[0].version >= floor) {
    await redis.set(`profile:${id}`, JSON.stringify({ version: rows[0].version, data: rows[0] }), 'EX', 600);
  }
  return rows[0];
}

export async function reserve(sku: string, qty: number) {
  const remaining = await redis.decrby(`stock:${sku}`, qty); // can go negative under race
  if (remaining < 0) {
    await redis.incrby(`stock:${sku}`, qty); // compensating, but window already oversold others
    throw new Error('out of stock');
  }
  return { sku, qty };
}

