const sha = await redis.scriptLoad(luaSource);
export async function reserve(sku: string, qty: number, reservationId: string) {
  const expireAt = Date.now() + 15 * 60 * 1000;
  const result = await redis.evalsha(sha, 2, `stock:${sku}`, `resv:${sku}`, qty, reservationId, expireAt) as number;
  if (result < 0) throw new OutOfStockError(sku);
  return { sku, qty, reservationId, expireAt };
}

export async function reapExpired() {
  const now = Date.now();
  const expired = await redis.zrangebyscore('resv:expiry', 0, now);
  for (const member of expired) {
    const [resvKey, reservationId] = member.split('|');
    const sku = resvKey.split(':')[1];
    const tx = redis.multi();
    const qty = await redis.hget(resvKey, reservationId);
    if (qty) {
      tx.incrby(`stock:${sku}`, Number(qty)); // release back to available
      tx.hdel(resvKey, reservationId);
      tx.zrem('resv:expiry', member);
      await tx.exec();
    }
  }
}

export async function commit(orderId: string, sku: string, qty: number, reservationId: string) {
  const added = await redis.sadd('committed:resv', reservationId); // 1 if new, 0 if already committed
  if (added === 0) return { idempotent: true };
  await pool.query(
    'INSERT INTO outbox_events(event_id, topic, aggregate_id, payload) VALUES (gen_random_uuid(), $1, $2, $3)',
    ['inventory.committed', sku, JSON.stringify({ orderId, sku, qty, reservationId })]
  );
  await redis.hdel(`resv:${sku}`, reservationId); // reservation becomes a permanent consumption
  return { idempotent: false };
}

