import { randomUUID } from 'crypto';
export async function confirm(apptId: string) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    await client.query('UPDATE appointments SET status=$1 WHERE id=$2', ['confirmed', apptId]);
    await client.query(
      `INSERT INTO reminders(appointment_id, idempotency_key) VALUES ($1, $2)
       ON CONFLICT (appointment_id) DO NOTHING`, [apptId, randomUUID()]
    );
    await client.query('COMMIT');
  } catch (e) { await client.query('ROLLBACK'); throw e; }
  finally { client.release(); }
}

export async function dispatchReminders() {
  const { rows } = await pool.query(
    `SELECT r.id, r.idempotency_key, a.email, a.status, a.id as appt_id
     FROM reminders r JOIN appointments a ON a.id = r.appointment_id
     WHERE r.status='pending' FOR UPDATE SKIP LOCKED LIMIT 100`
  );
  for (const r of rows) {
    if (r.status !== 'confirmed') {
      await pool.query(`UPDATE reminders SET status='suppressed' WHERE id=$1`, [r.id]); // cancelled => no email
      continue;
    }
    await sendgrid.send({ to: r.email, template: 'reminder', idempotencyKey: r.idempotency_key });
    await pool.query(`UPDATE reminders SET status='sent', sent_at=now() WHERE id=$1 AND status='pending'`, [r.id]);
  }
}

from rest_framework.views import APIView
from accounts.models import Account

class TransferView(APIView):
    def post(self, request):
        src = Account.objects.get(id=request.data['from'])
        dst = Account.objects.get(id=request.data['to'])
        amount = request.data['amount']
        if src.balance < amount:
            return Response({'error': 'insufficient'}, status=400)
        src.balance -= amount
        dst.balance += amount
        src.save()  # not atomic with dst.save; concurrent transfers lose updates
        dst.save()
        return Response({'ok': True})

from django.db import transaction
from rest_framework.views import APIView
from accounts.models import Account
from .models import TransferKey

class TransferView(APIView):
    def post(self, request):
        key = request.headers['Idempotency-Key']
        amount = request.data['amount']
        ids = sorted([request.data['from'], request.data['to']])  # deterministic lock order
        try:
            with transaction.atomic():
                if TransferKey.objects.filter(key=key).exists():
                    return Response({'ok': True, 'replay': True})
                locked = {a.id: a for a in Account.objects.select_for_update().filter(id__in=ids)}
                src, dst = locked[request.data['from']], locked[request.data['to']]
                if src.balance < amount:
                    return Response({'error': 'insufficient'}, status=400)
                src.balance -= amount
                dst.balance += amount
                src.save(update_fields=['balance'])
                dst.save(update_fields=['balance'])
                TransferKey.objects.create(key=key, src_id=src.id, dst_id=dst.id, amount=amount)
        except IntegrityError:
            return Response({'ok': True, 'replay': True})  # concurrent duplicate lost the unique key
        return Response({'ok': True})

