export async function runSaga(saga: Saga) {
  for (let i = saga.currentStep; i < saga.steps.length; i++) {
    try {
      await saga.steps[i].execute(saga.ctx, idemKey(saga.id, i)); // idempotent per step
      await pool.query('UPDATE sagas SET current_step=$2 WHERE id=$1', [saga.id, i + 1]);
    } catch (err) {
      await scheduleRetry(saga.id, i, err);
      return; // hand off to scheduler; do not drop
    }
  }
  await markComplete(saga.id);
}

export async function scheduleRetry(sagaId: string, step: number, err: unknown) {
  const { rows } = await pool.query('SELECT attempt FROM saga_retries WHERE saga_id=$1', [sagaId]);
  const attempt = (rows[0]?.attempt ?? 0) + 1;
  if (attempt > 6) {
    await pool.query('INSERT INTO saga_dead_letter(saga_id, failed_step, attempts, last_error) VALUES ($1,$2,$3,$4)',
      [sagaId, step, attempt, String(err)]);
    await pool.query('DELETE FROM saga_retries WHERE saga_id=$1', [sagaId]);
    return;
  }
  const backoffMs = Math.min(2 ** attempt * 1000, 5 * 60_000);
  const jitter = Math.random() * backoffMs * 0.3;
  const next = new Date(Date.now() + backoffMs + jitter);
  await pool.query(
    `INSERT INTO saga_retries(saga_id, attempt, next_run_at, last_error) VALUES ($1,$2,$3,$4)
     ON CONFLICT (saga_id) DO UPDATE SET attempt=$2, next_run_at=$3, last_error=$4`,
    [sagaId, attempt, next, String(err)]
  );
}

export async function runDueRetries() {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const { rows } = await client.query(
      `SELECT saga_id FROM saga_retries WHERE next_run_at <= now() ORDER BY next_run_at
       FOR UPDATE SKIP LOCKED LIMIT 50`
    );
    for (const r of rows) {
      const saga = await loadSaga(r.saga_id); // includes current_step
      await runSaga(saga); // resumes from the failed step
    }
    await client.query('COMMIT');
  } catch (e) { await client.query('ROLLBACK'); throw e; }
  finally { client.release(); }
}

