@Injectable()
export class CancelService {
  constructor(private store: SagaStore, private payments: PaymentsClient, private inventory: InventoryClient, private loyalty: LoyaltyClient, private orders: OrdersRepo) {}
  async cancel(orderId: string) {
    const saga = await this.store.upsert(orderId); // idempotent create
    if (!saga.refunded) { await this.payments.refund(orderId, orderId /* idem key */); await this.store.mark(orderId, 'refunded'); }
    if (!saga.restocked) { await this.inventory.restock(orderId, orderId); await this.store.mark(orderId, 'restocked'); }
    if (!saga.pointsRevoked) { await this.loyalty.revoke(orderId, orderId); await this.store.mark(orderId, 'pointsRevoked'); }
    await this.orders.markCancelled(orderId);
    await this.store.mark(orderId, 'completed');
  }
}

