export class SagaStore {
  constructor(@InjectRepository(CancelSaga) private repo: Repository<CancelSaga>) {}
  async upsert(orderId: string) {
    await this.repo.createQueryBuilder().insert().into(CancelSaga)
      .values({ orderId }).orIgnore().execute(); // ON CONFLICT DO NOTHING
    return this.repo.findOneByOrFail({ orderId });
  }
  async mark(orderId: string, step: string) {
    await this.repo.update({ orderId }, { [step]: true });
  }
}

