export async function reconcile() {
  const { rows } = await coordinator.query(
    `SELECT saga_id, order_shard, payment_shard FROM checkout_intents
     WHERE state='pending' AND created_at < now() - interval '2 minutes'
     FOR UPDATE SKIP LOCKED LIMIT 100`
  );
  for (const i of rows) {
    const hasOrder = await shard(i.order_shard).exists('orders', i.saga_id);
    const hasPayment = await shard(i.payment_shard).exists('payments', i.saga_id);
    if (hasOrder && hasPayment) { await markCommitted(i.saga_id); continue; }
    if (hasOrder && !hasPayment) { await retryPaymentInsert(i.saga_id); } // forward-recover
    else if (!hasOrder && hasPayment) { await voidPayment(i.saga_id); }   // order never landed -> void
    else { await markVoid(i.saga_id); }
  }
}

func process(job Job) error {
	sandbox, err := cloud.Provision(job.Spec) // non-idempotent; runs again on redelivery
	if err != nil {
		return err
	}
	return db.Exec("INSERT INTO sandboxes(job_id, sandbox_id) VALUES ($1,$2)", job.ID, sandbox.ID)
}

func process(ctx context.Context, job Job, workerID string) error {
	tx, err := db.BeginTx(ctx, nil)
	if err != nil { return err }
	defer tx.Rollback()
	var status string
	err = tx.QueryRow(
		`INSERT INTO job_ledger(job_id, worker_id) VALUES ($1,$2)
		 ON CONFLICT (job_id) DO UPDATE SET worker_id = job_ledger.worker_id
		 RETURNING status`, job.ID, workerID).Scan(&status)
	if err != nil { return err }
	if status == "done" { tx.Commit(); return nil } // already provisioned: ack & skip
	if status == "claimed" && !claimIsStale(ctx, job.ID) { tx.Commit(); return nil } // another worker owns it
	if err = tx.Commit(); err != nil { return err }
	// we own the claim: provision exactly once
	sandbox, err := cloud.Provision(job.Spec)
	if err != nil { return err }
	_, err = db.Exec(`UPDATE job_ledger SET status='done', sandbox_id=$2 WHERE job_id=$1`, job.ID, sandbox.ID)
	return err
}

func claimIsStale(ctx context.Context, jobID string) bool {
	var age time.Duration
	row := db.QueryRowContext(ctx, `SELECT now() - claimed_at FROM job_ledger WHERE job_id=$1`, jobID)
	_ = row.Scan(&age)
	return age > leaseTimeout // a crashed worker's claim becomes reclaimable after the lease
}

