export async function approve(deptId: string, expenseId: string, amount: number, idemKey: string) {
  for (let attempt = 0; attempt < 3; attempt++) {
    const client = await pool.connect();
    try {
      await client.query('BEGIN ISOLATION LEVEL SERIALIZABLE');
      const ins = await client.query(
        `INSERT INTO approvals(expense_id, dept_id, amount, idem_key) VALUES ($1,$2,$3,$4)
         ON CONFLICT (idem_key) DO NOTHING RETURNING id`, [expenseId, deptId, amount, idemKey]
      );
      if (ins.rowCount === 0) { await client.query('COMMIT'); return { replay: true }; }
      const upd = await client.query(
        `UPDATE dept_budgets SET spent = spent + $2 WHERE id=$1 AND spent + $2 <= cap`, [deptId, amount]
      );
      if (upd.rowCount === 0) { await client.query('ROLLBACK'); throw new OverBudgetError(deptId); }
      await client.query('COMMIT');
      return { replay: false };
    } catch (e: any) {
      await client.query('ROLLBACK');
      if (e.code === '40001') continue; // serialization failure -> retry
      throw e;
    } finally { client.release(); }
  }
  throw new Error('approval contention exceeded retries');
}

