  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const { rows } = await client.query(
      `SELECT id, sku, version, delta FROM stock_outbox WHERE published_at IS NULL
       ORDER BY id FOR UPDATE SKIP LOCKED LIMIT $1`, [batch]
    );
    for (const r of rows) {
      const ack = await inventoryClient.updateStock({ sku: r.sku, version: r.version, delta: r.delta });
      if (!ack.applied && ack.reason !== 'stale') throw new Error('central rejected, will retry');
    }
    if (rows.length) await client.query('UPDATE stock_outbox SET published_at=now() WHERE id = ANY($1)', [rows.map(r => r.id)]);
    await client.query('COMMIT');
    return rows.length;
  } catch (e) { await client.query('ROLLBACK'); throw e; }
  finally { client.release(); }
}

// central UpdateStock handler applies version-guarded
async function UpdateStock(req: { sku: string; version: number; delta: number }) {
  const { rowCount } = await pool.query(
    `UPDATE central_stock SET qty = qty + $3, version = $2 WHERE sku=$1 AND $2 > version`,
    [req.sku, req.version, req.delta]
  );
  return { applied: rowCount === 1, reason: rowCount === 0 ? 'stale' : 'ok' };
}

