export async function checkout(formData: FormData) {
  const cartId = formData.get('cartId') as string;
  const key = formData.get('idempotencyKey') as string;
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const claim = await client.query(
      `INSERT INTO checkout_keys(key, cart_id) VALUES ($1,$2) ON CONFLICT (key) DO NOTHING RETURNING key`, [key, cartId]
    );
    if (claim.rowCount === 0) {
      const { rows } = await client.query('SELECT order_id FROM checkout_keys WHERE key=$1', [key]);
      await client.query('COMMIT');
      if (rows[0].order_id) redirect(`/orders/${rows[0].order_id}`);
      throw new Error('checkout in progress');
    }
    await client.query('COMMIT');
  } finally { client.release(); }
  const cart = await loadCart(cartId);
  const charge = await stripe.charges.create({ amount: cart.total, source: cart.token }, { idempotencyKey: key });
  const { rows } = await pool.query('INSERT INTO orders(cart_id, charge_id, total) VALUES ($1,$2,$3) RETURNING id', [cartId, charge.id, cart.total]);
  await pool.query('UPDATE checkout_keys SET order_id=$2 WHERE key=$1', [key, rows[0].id]);
  redirect(`/orders/${rows[0].id}`);
}

