export class NonRetryableError extends Error {}
export class RetryableError extends Error {}

export function classify(e: unknown): 'retry' | 'dlq' {
  if (e instanceof NonRetryableError) return 'dlq';
  if (e instanceof SyntaxError) return 'dlq'; // malformed JSON is permanent
  return 'retry';
}

await consumer.run({
  eachMessage: async ({ message, topic, partition }) => {
    try {
      const evt = parseAndValidate(message.value); // throws NonRetryableError on bad data
      await withRetry(() => sendNotification(evt.userId, evt.body), { max: 5, baseMs: 200 });
    } catch (e) {
      const decision = classify(e);
      if (decision === 'retry') throw e; // let the broker redeliver within reason... but bounded below
      await dlqProducer.send({
        topic: `${topic}.dlq`,
        messages: [{ key: message.key, value: message.value, headers: {
          'x-error': String(e), 'x-source-topic': topic, 'x-source-partition': String(partition), 'x-source-offset': message.offset
        } }]
      });
      // offset auto-commits after this returns -> partition advances past the poison message
    }
  }
});

export async function withRetry<T>(fn: () => Promise<T>, opts: { max: number; baseMs: number }): Promise<T> {
  let lastErr: unknown;
  for (let i = 0; i < opts.max; i++) {
    try { return await fn(); }
    catch (e) {
      lastErr = e;
      if (classify(e) === 'dlq') throw e; // don't waste retries on permanent errors
      await new Promise(r => setTimeout(r, opts.baseMs * 2 ** i));
    }
  }
  throw new NonRetryableError(`exhausted retries: ${String(lastErr)}`); // exhausted -> DLQ
}

export async function project() {
  const events = await eventStore.readAll(); // re-reads from the beginning on restart
  for (const e of events) {
    if (e.type === 'Credited') await db.query('UPDATE balances SET amount = amount + $1 WHERE account=$2', [e.amount, e.account]);
    if (e.type === 'Debited') await db.query('UPDATE balances SET amount = amount - $1 WHERE account=$2', [e.amount, e.account]);
  }
}

