);

export async function projectAccount(account: string) {
  const { rows } = await pool.query('SELECT last_seq FROM balances WHERE account=$1', [account]);
  let pos = rows[0]?.last_seq ?? 0;
  const events = await eventStore.readFrom(account, pos + 1); // resume from stored position
  for (const e of events) {
    const client = await pool.connect();
    try {
      await client.query('BEGIN');
      const delta = e.type === 'Credited' ? e.amount : -e.amount;
      const { rowCount } = await client.query(
        `UPDATE balances SET amount = amount + $1, last_seq = $2 WHERE account=$3 AND last_seq = $4`,
        [delta, e.seq, account, e.seq - 1] // applies only the next event in order
      );
      await client.query('COMMIT');
      if (rowCount === 1) pos = e.seq; else break; // out-of-order/duplicate: stop, re-read
    } catch (err) { await client.query('ROLLBACK'); throw err; }
    finally { client.release(); }
  }
}

export async function rebuild(account: string) {
  const snap = await loadSnapshot(account); // {amount, last_seq} or zero
  await pool.query('INSERT INTO balances(account, amount, last_seq) VALUES ($1,$2,$3) ON CONFLICT (account) DO UPDATE SET amount=$2, last_seq=$3', [account, snap.amount, snap.lastSeq]);
  await projectAccount(account); // replay events after the snapshot
}

