export async function sync(noteId: string, body: string, clientUpdatedAt: number) {
  const { rows } = await db.query('SELECT updated_at FROM notes WHERE id=$1', [noteId]);
  if (clientUpdatedAt > rows[0].updated_at) {
    await db.query('UPDATE notes SET body=$1, updated_at=$2 WHERE id=$3', [body, clientUpdatedAt, noteId]); // clobbers concurrent edits
  }
}

export type Block = { id: string; text: string; lamport: number; replica: string; tombstone: boolean };
export type NoteCRDT = { blocks: Record<string, Block> };

export function merge(a: NoteCRDT, b: NoteCRDT): NoteCRDT {
  const out: NoteCRDT = { blocks: { ...a.blocks } };
  for (const id in b.blocks) {
    const cur = out.blocks[id];
    const inc = b.blocks[id];
    if (!cur || inc.lamport > cur.lamport || (inc.lamport === cur.lamport && inc.replica > cur.replica)) {
      out.blocks[id] = inc; // deterministic LWW per block; tie-break by replica id
    }
  }
  return out; // commutative + idempotent => converges regardless of merge order
}

export function materialize(n: NoteCRDT): string {
  return Object.values(n.blocks).filter(b => !b.tombstone).sort((x, y) => x.id.localeCompare(y.id)).map(b => b.text).join('\n');
}

export async function sync(noteId: string, delta: NoteCRDT) {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const { rows } = await client.query('SELECT state FROM notes WHERE id=$1 FOR UPDATE', [noteId]);
    const merged = merge(rows[0].state as NoteCRDT, delta); // never clobbers; merges
    await client.query('UPDATE notes SET state=$1, body=$2 WHERE id=$3', [merged, materialize(merged), noteId]);
    await client.query('COMMIT');
    return merged;
  } catch (e) { await client.query('ROLLBACK'); throw e; }
  finally { client.release(); }
}

