@MessagePattern('invoice.issued')
async handle(@Payload() evt: InvoiceEvent, @Ctx() ctx: RmqContext) {
  const msg = ctx.getMessage();
  const messageId = msg.properties.messageId;
  const channel = ctx.getChannelRef();
  try {
    await this.dataSource.transaction(async (tx) => {
      await tx.query('INSERT INTO message_inbox(message_id, consumer) VALUES ($1, $2)', [messageId, 'invoice-ledger']);
      await this.ledger.createEntry(evt, tx); // same tx as the dedupe insert
    });
    channel.ack(msg);
  } catch (e: any) {
    if (e.code === '23505') { channel.ack(msg); return; } // already processed: dedupe, ack
    channel.nack(msg, false, true); // transient: requeue, nothing committed so safe
  }
}

