export async function onboard(userId: string) {
  await createProfile(userId);
  const kyc = await kycProvider.check(userId); // blocks; may need manual review
  if (kyc.status === 'pass') {
    await provisionAccount(userId);
  } else if (kyc.status === 'review') {
    await routeToManualReview(userId); // fire-and-forget; saga context lost here
  } else {
    await rejectUser(userId);
  }
}

CREATE TABLE onboarding_sagas (
  user_id UUID PRIMARY KEY,
  state TEXT NOT NULL DEFAULT 'created',
  account_provisioned BOOLEAN NOT NULL DEFAULT false,
  kyc_deadline_at TIMESTAMPTZ,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX onboarding_kyc_overdue ON onboarding_sagas (kyc_deadline_at) WHERE state='kyc_pending';

export async function onboard(userId: string) {
  await upsertSaga(userId, 'created');
  await createProfile(userId); // idempotent
  await setState(userId, 'kyc_pending', { kyc_deadline_at: new Date(Date.now() + KYC_TIMEOUT_MS) });
  let kyc;
  try { kyc = await withTimeout(kycProvider.check(userId), KYC_CALL_TIMEOUT); }
  catch { return; /* leave kyc_pending; sweeper escalates */ }
  if (kyc.status === 'pass') { await provisionAccount(userId); await setState(userId, 'active', { account_provisioned: true }); }
  else if (kyc.status === 'review') { await setState(userId, 'awaiting_review'); }
  else { await setState(userId, 'rejected'); }
}

export async function onReviewDecision(userId: string, decision: 'approve' | 'reject') {
  const saga = await loadSaga(userId);
  if (saga.state !== 'awaiting_review') return; // idempotent: ignore stale/duplicate decisions
  if (decision === 'approve') {
    await provisionAccount(userId); // idempotent
    await setState(userId, 'active', { account_provisioned: true });
  } else {
    if (saga.account_provisioned) await revokeAccount(userId); // compensation
    await setState(userId, 'rejected');
  }
}

export async function escalateOverdueKyc() {
  const { rows } = await pool.query(
    `SELECT user_id FROM onboarding_sagas WHERE state='kyc_pending' AND kyc_deadline_at <= now()
     FOR UPDATE SKIP LOCKED LIMIT 50`
  );
  for (const r of rows) {
    const status = await kycProvider.status(r.user_id); // reconcile actual KYC outcome
    if (status.resolved) await resumeFromKyc(r.user_id, status);
    else { await setState(r.user_id, 'awaiting_review'); await routeToManualReview(r.user_id); }
  }
}

async function like(postId, userId) {
  const post = await db.collection('posts').findOne({ _id: postId });
  post.likeCount = post.likeCount + 1; // read-modify-write race
  await db.collection('posts').replaceOne({ _id: postId }, post);
  await db.collection('likes').insertOne({ postId, userId }); // no uniqueness; double-like possible
}

async function like(postId, userId) {
  try {
    await db.collection('likes').insertOne({ postId, userId, createdAt: new Date() }); // unique gate
  } catch (e) {
    if (e.code === 11000) return { liked: true, idempotent: true }; // already liked: no counter change
    throw e;
  }
  await db.collection('posts').updateOne({ _id: postId }, { $inc: { likeCount: 1 } }); // atomic, no lost updates
  return { liked: true, idempotent: false };
}

async function unlike(postId, userId) {
  const res = await db.collection('likes').deleteOne({ postId, userId });
  if (res.deletedCount === 1) await db.collection('posts').updateOne({ _id: postId }, { $inc: { likeCount: -1 } });
}

async function reconcilePost(postId) {
  const trueCount = await db.collection('likes').countDocuments({ postId });
  await db.collection('posts').updateOne({ _id: postId }, { $set: { likeCount: trueCount } });
}
